5 驱动类型和气缸数量的关系分析
驱动类型和气缸数量不独立。
4缸，72%前驱，28%四驱;
6缸，54%前驱， 41%四驱，5%后驱;
8缸，1%前驱， 69%四驱，30%后驱。

代码
library(tidyverse)
library(gt)
library(patchwork)
library(ggrepel)

# ── 读取数据 ──────────────────────────────────────────────
library(readxl)
raw &lt;- read_excel("df_24hr.xlsx")

# ── 清洗与整理 ────────────────────────────────────────────
df &lt;- raw |&gt;
  rename(
    姓名       = 姓名,
    学号       = 学号,
    班级       = 所属行政班,
    开课次数   = 开课次数,
    签到次数   = 签到次数,
    作业项数   = 作业和测验项数,
    作业提交数 = 作业和测验提交项数
  ) |&gt;
  mutate(
    # 原始数据为 0–1，乘 100 转为百分制
    签到率     = 签到率     * 100,
    作业提交率 = 作业提交率 * 100,
    班级简称 = case_when(
      str_detect(班级, "1$") ~ "人力资源1班",
      str_detect(班级, "2$") ~ "人力资源2班",
      TRUE ~ 班级
    ),
    综合参与度 = (签到率 + 作业提交率) / 2,
    预警等级 = case_when(
      综合参与度 &lt; 50 ~ "严重预警（&lt;50%）",
      综合参与度 &lt; 70 ~ "中度预警（50–70%）",
      综合参与度 &lt; 85 ~ "轻度预警（70–85%）",
      TRUE            ~ "正常（≥85%）"
    ),
    预警等级 = factor(预警等级, levels = c(
      "严重预警（&lt;50%）", "中度预警（50–70%）",
      "轻度预警（70–85%）", "正常（≥85%）"
    ))
  )

# 颜色方案（马卡龙色）
col_warning &lt;- c(
  "严重预警（&lt;50%）"   = "#F4A7B9",   # 玫瑰粉
  "中度预警（50–70%）" = "#FDBF8B",   # 蜜桃橙
  "轻度预警（70–85%）" = "#FFF0A0",   # 柠檬黄
  "正常（≥85%）"       = "#A8D8B9"    # 薄荷绿
)

# gt 表格通用样式函数
gt_style &lt;- function(gt_tbl) {
  gt_tbl |&gt;
    tab_options(
      table.width                        = pct(100),
      table.border.top.style             = "solid",
      table.border.top.width             = px(2),
      table.border.top.color             = "#4472C4",
      table.border.bottom.style          = "solid",
      table.border.bottom.width          = px(2),
      table.border.bottom.color          = "#4472C4",
      column_labels.border.bottom.width  = px(2),
      column_labels.border.bottom.color  = "#4472C4",
      data_row.padding                   = px(8),
      table.font.size                    = px(13)
    ) |&gt;
    tab_style(
      style = list(
        cell_fill(color = "#4472C4"),
        cell_text(color = "white", weight = "bold", size = px(13))
      ),
      locations = cells_column_labels()
    )
}

# 预警表格辅助函数
make_warn_table &lt;- function(data, header_color, row_color, title_text) {
  if (nrow(data) == 0) {
    cat("✅ 无此级别预警学生。")
    return(invisible(NULL))
  }
  data |&gt;
    select(学号, 班级简称, 签到率, 作业提交率, 综合参与度) |&gt;
    arrange(综合参与度) |&gt;
    gt() |&gt;
    tab_header(title = title_text) |&gt;
    cols_label(
      学号       = "学号",
      班级简称   = "班级",
      签到率     = "签到率",
      作业提交率 = "作业提交率",
      综合参与度 = "综合参与度"
    ) |&gt;
    fmt_number(
      columns  = c(签到率, 作业提交率, 综合参与度),
      decimals = 1,
      pattern  = "{x}%"
    ) |&gt;
    cols_align(align = "center") |&gt;
    cols_align(align = "left", columns = 学号) |&gt;
    tab_style(
      style = list(
        cell_fill(color = header_color),
        cell_text(color = "white", weight = "bold", size = px(13))
      ),
      locations = cells_column_labels()
    ) |&gt;
    tab_style(
      style = cell_fill(color = row_color),
      locations = cells_body()
    ) |&gt;
    tab_options(
      table.width                       = pct(100),
      table.border.top.style            = "solid",
      table.border.top.width            = px(2),
      table.border.top.color            = header_color,
      table.border.bottom.style         = "solid",
      table.border.bottom.width         = px(2),
      table.border.bottom.color         = header_color,
      column_labels.border.bottom.width = px(2),
      column_labels.border.bottom.color = header_color,
      data_row.padding                  = px(8),
      table.font.size                   = px(13)
    )
}

